qry:select.qry:xquery:
	for $r in sql('
	SELECT ORG02_ESTRUC_PERS.oi_personal_emp,
	ORG02_ESTRUC_PERS.oi_estructura,
	PER02_PERSONAL_EMP.e_numero_legajo,
	PER01_PERSONAL.d_ape_y_nom
	FROM ORG02_ESTRUC_PERS, PER02_PERSONAL_EMP, PER01_PERSONAL,
	TTA09_LIQUIDACION, TTA10_LIQUIDACPERS, 
	TTA10_LIQUIDACJOR, TTA10_LIQUIDACPROC
	JOIN ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
	PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal,
	TTA10_LIQUIDACPERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
	TTA09_LIQUIDACION.oi_liquidacion INNER TTA10_LIQUIDACPERS.oi_liquidacion,
	TTA10_LIQUIDACJOR.oi_liquidacjor INNER TTA10_LIQUIDACPROC.oi_liquidacjor,
	TTA10_LIQUIDACPERS.oi_liquidacionpers INNER TTA10_LIQUIDACJOR.oi_liquidacionpers
	WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
	AND TTA10_LIQUIDACPERS.oi_liquidacion = {#FILTRO:@oi_liquidacion}		  
  {%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
		{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
		{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:TIPOHORAS/TIPOHORA/@id)!='') 
		{% AND TTA10_LIQUIDACPROC.oi_tipohora in ({%=string(#FILTRO:TIPOHORAS/TIPOHORA/@id)%}) %} 
		{%  %} 
	%}			
	GROUP BY ORG02_ESTRUC_PERS.oi_personal_emp, ORG02_ESTRUC_PERS.oi_estructura,
	PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom
')/ROWS/ROW

	for $r in sql('
			SELECT TTA10_LIQUIDACJOR.f_fecjornada,
			TTA10_LIQUIDACPROC.oi_tipohora,
			SUM(TTA10_LIQUIDACPROC.n_cantidadhs) AS cantidad					
			FROM TTA09_LIQUIDACION, TTA10_LIQUIDACPERS, 
			TTA10_LIQUIDACJOR, TTA10_LIQUIDACPROC
			JOIN TTA09_LIQUIDACION.oi_liquidacion INNER TTA10_LIQUIDACPERS.oi_liquidacion,
			TTA10_LIQUIDACJOR.oi_liquidacjor INNER TTA10_LIQUIDACPROC.oi_liquidacjor,
			TTA10_LIQUIDACPERS.oi_liquidacionpers INNER TTA10_LIQUIDACJOR.oi_liquidacionpers
			WHERE TTA10_LIQUIDACPERS.oi_personal_emp = {#PARAM:@oi_personal_emp}
			AND TTA09_LIQUIDACION.oi_liquidacion = {#FILTRO:@oi_liquidacion}
			{%? (#FILTRO:@f_desde != '') {% AND TTA10_LIQUIDACJOR.f_fecjornada >= {DateTime(#FILTRO:@f_desde)} %} {%  %}   %}
			{%? (#FILTRO:@f_hasta != '') {% AND TTA10_LIQUIDACJOR.f_fecjornada <= {DateTime(Number(DateTime(#FILTRO:@f_hasta))+1)} %} {%  %}   %}
			{%? (string(#FILTRO:TIPOHORAS/TIPOHORA/@id)!='') 
				{% AND TTA10_LIQUIDACPROC.oi_tipohora in ({%=string(#FILTRO:TIPOHORAS/TIPOHORA/@id)%}) %} 
				{%  %} 
			%}
			GROUP BY TTA10_LIQUIDACJOR.f_fecjornada, TTA10_LIQUIDACPROC.oi_tipohora
')/ROWS/ROW
